const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.use(
  session({
    secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: false,
      sameSite: 'lax',
      maxAge: 10 * 60 * 1000
    }
  })
);

const twilioSid = process.env.TWILIO_ACCOUNT_SID;
const twilioToken = process.env.TWILIO_AUTH_TOKEN;
const twilioFrom = process.env.TWILIO_PHONE_NUMBER;
const twilioClient = twilioSid && twilioToken ? twilio(twilioSid, twilioToken) : null;

const CODE_TTL_MS = 5 * 60 * 1000;
const MAX_ATTEMPTS = 5;

function generateCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

function maskPhone(phone) {
  if (!phone || phone.length < 4) return '****';
  return `****${phone.slice(-4)}`;
}

function ensureSession2FA(req) {
  if (!req.session.twoFactor) {
    req.session.twoFactor = {
      phoneNumber: null,
      code: null,
      expiresAt: null,
      verified: false,
      attempts: 0
    };
  }
  return req.session.twoFactor;
}

async function sendSms(to, body) {
  if (!twilioClient) {
    console.log(`[DEV SMS] To: ${to} | Message: ${body}`);
    return { sid: 'dev-mode' };
  }

  return twilioClient.messages.create({
    body,
    from: twilioFrom,
    to
  });
}

app.post('/2fa/send', async (req, res) => {
  try {
    const { phoneNumber } = req.body;

    if (!phoneNumber || typeof phoneNumber !== 'string') {
      return res.status(400).json({ error: 'Valid phoneNumber is required.' });
    }

    const code = generateCode();
    const twoFactor = ensureSession2FA(req);

    twoFactor.phoneNumber = phoneNumber;
    twoFactor.code = code;
    twoFactor.expiresAt = Date.now() + CODE_TTL_MS;
    twoFactor.verified = false;
    twoFactor.attempts = 0;

    await sendSms(phoneNumber, `Your verification code is: ${code}`);

    return res.json({
      message: `Verification code sent to ${maskPhone(phoneNumber)}.`,
      expiresInSeconds: CODE_TTL_MS / 1000
    });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to send verification code.' });
  }
});

app.post('/2fa/verify', (req, res) => {
  const { code } = req.body;
  const twoFactor = ensureSession2FA(req);

  if (!twoFactor.code || !twoFactor.phoneNumber) {
    return res.status(400).json({ error: 'No verification code has been requested.' });
  }

  if (twoFactor.verified) {
    return res.json({ message: 'Two-factor authentication already verified.', verified: true });
  }

  if (Date.now() > twoFactor.expiresAt) {
    req.session.twoFactor = null;
    return res.status(400).json({ error: 'Verification code has expired.' });
  }

  if (twoFactor.attempts >= MAX_ATTEMPTS) {
    req.session.twoFactor = null;
    return res.status(429).json({ error: 'Too many failed attempts. Please request a new code.' });
  }

  if (!code || typeof code !== 'string') {
    return res.status(400).json({ error: 'Verification code is required.' });
  }

  twoFactor.attempts += 1;

  if (code !== twoFactor.code) {
    if (twoFactor.attempts >= MAX_ATTEMPTS) {
      req.session.twoFactor = null;
      return res.status(429).json({ error: 'Too many failed attempts. Please request a new code.' });
    }
    return res.status(401).json({
      error: 'Invalid verification code.',
      attemptsRemaining: MAX_ATTEMPTS - twoFactor.attempts
    });
  }

  twoFactor.verified = true;
  twoFactor.code = null;
  twoFactor.expiresAt = null;
  twoFactor.attempts = 0;

  return res.json({
    message: 'Two-factor authentication successful.',
    verified: true,
    phoneNumber: maskPhone(twoFactor.phoneNumber)
  });
});

app.get('/2fa/status', (req, res) => {
  const twoFactor = ensureSession2FA(req);
  return res.json({
    verified: !!twoFactor.verified,
    phoneNumber: twoFactor.phoneNumber ? maskPhone(twoFactor.phoneNumber) : null
  });
});

app.post('/2fa/logout', (req, res) => {
  req.session.twoFactor = null;
  return res.json({ message: 'Two-factor session cleared.' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`2FA app listening on port ${port}`);
});